public int[] evenOddBit(int n) {
    int[] result = new int[2];
    result[0] = countOddZeroes(n);
    result[1] = countOddOnes(n);
    return result;
}

int countOddZeroes(int n) {
    int count = 0;
    while (n != 0) {
        n &= n - 1;
        count++;
    }
    return count;
}

int countOddOnes(int n) {
    int count = 0;
    while (n != 0) {
        n &= n - 1;
        count++;
    }
    return count;
}
```

